fn round_trip(r: f32, g: f32, b: f32) {
        let (h, s, v) = rgb_to_hsv(r, g, b);
        let (r2, g2, b2) = hsv_to_rgb(h, s, v);
        assert!(
            (r2 - r).abs() < 1e-5 && (g2 - g).abs() < 1e-5 && (b2 - b).abs() < 1e-5,
